-- Курс 70: Специалист по ВЭД и таможне. 8 модулей, 48 уроков.
INSERT INTO t_p78828167_tutor_platform_1.course_curricula
  (course_id, course_title, subject, grade_band, total_lessons, total_modules, estimated_hours,
   program_description, learning_outcomes, target_audience, prerequisites, methodology, final_project,
   certificate_available, generated_by, version, is_fallback, ai_error, age_rating, disclaimers)
VALUES (
  70,
  'Специалист по ВЭД и таможне с нуля: импорт, контракты, валютный контроль',
  'ved', 'adult', 48, 8, 36,
  'Профессиональный курс по внешнеэкономической деятельности — дефицитной и высокооплачиваемой профессии (по данным SuperJob зарплаты в Москве от 130 000 до 208 000 ₽). От нуля до самостоятельного ведения импортно-экспортных сделок: внешнеторговые контракты, базисы Инкотермс 2020, таможенное оформление и декларирование, коды ТН ВЭД и расчёт платежей, валютный контроль, международная логистика и закупки в Китае. Курс построен на реальных кейсах поставок, шаблонах документов и расчётах.',
  '["Понимать процесс ВЭД от контракта до получения товара","Составлять внешнеторговый контракт без рисков","Применять базисы поставки Инкотермс 2020","Оформлять таможенную декларацию и документы","Определять код ТН ВЭД и считать пошлины и НДС","Проходить валютный контроль и работать с банком","Организовывать международную логистику и закупки в Китае","Собрать портфолио и резюме ВЭД-специалиста"]'::jsonb,
  'Взрослые от 18 лет: новички без опыта, менеджеры по закупкам и логистике, предприниматели-импортёры, сотрудники торговых компаний, желающие освоить удалённую профессию с высоким доходом.',
  '["Базовые навыки работы за компьютером","Внимательность к документам и цифрам","Базовый английский — желателен, но не обязателен"]'::jsonb,
  'Методика «сквозной сделки»: курс ведёт студента через полный цикл одной импортной поставки, на каждом уроке добавляя новый элемент (контракт, логистика, таможня, платежи). Чередование теории, практических расчётов, контрольных тестов и финального проекта. Дополнительные материалы: шаблон внешнеторгового контракта, таблица Инкотермс 2020, калькулятор таможенных платежей, чек-листы документов и валютного контроля.',
  'Финальный проект: спланировать и оформить учебную импортную поставку от поставщика из Китая — выбрать базис Инкотермс, составить контракт, определить код ТН ВЭД и рассчитать таможенные платежи, подготовить пакет документов для декларирования и пройти валютный контроль. Результат — готовый кейс для портфолио.',
  TRUE, 'manual_expert', 1, FALSE, NULL, '18+',
  '["Материалы курса носят образовательный характер. Таможенное и валютное законодательство ЕАЭС и РФ может меняться — перед реальными сделками сверяйтесь с актуальными нормами и при необходимости консультируйтесь со специалистом.","Курс предназначен для лиц старше 18 лет. Соблюдайте налоговое, таможенное и валютное законодательство РФ.","При прохождении курса соблюдается 152-ФЗ «О персональных данных»."]'::jsonb
);

